212→    if (history.length === 0) return 0;
213→
214→    const now = new Date();
215→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
216→
217→    const projectCreationDates = new Map<string, Date>();
218→
219→    history.forEach(h => {
220→        let hostname;
221→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
222→
223→        const analysisDate = new Date(h.timestamp);
224→
225→        if (!projectCreationDates.has(hostname)) {
226→            projectCreationDates.set(hostname, analysisDate);
227→        } else {
228→            if (analysisDate < projectCreationDates.get(hostname)!) {
229→                projectCreationDates.set(hostname, analysisDate);
230→            }
