335→            if (prev.length === 0) return prev;
336→            const updated = { ...prev[0], preGenerated };
337→            db.update(0, updated);
338→            return [updated, ...prev.slice(1)];
339→          });
340→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
341→          setMegaStatus('completed');
342→        } else {
343→          setMegaStatus('failed');
344→        }
345→      }).catch(() => setMegaStatus('failed'));
346→
347→      setResultsTab('details');
348→      navigateTo('projects');
349→    } catch (error) {
350→      console.error("Analysis failed", error);
351→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
