510→        return <SMCStudio onBack={goBack} user={user} onDeductCredits={handleDeductCredits} library={smcLibrary} onAddToLibrary={handleAddToSmcLibrary} onNavigateToPublisher={handleNavigateToPublisher} onNavigateToDirectory={handleNavigateToDirectory} />;
511→      case 'blog-optimizer':
512→        return <BlogOptimizer onBack={goBack} user={user} onDeductCredits={handleDeductCredits} onNavigateToPublisher={handleNavigateToPublisher} />;
513→      case 'schema-org':
514→        return <SchemaOrg onBack={goBack} history={history} user={user} onDeductCredits={handleDeductCredits} savedFiles={schemaLibrary} onSaveFile={handleAddToSchemaLibrary} />;
